namespace LeetCodeDemos.Problems
{
    // https://leetcode.com/problems/substring-with-concatenation-of-all-words/description/
    internal class FindConcatenatedSubstring : ISolutionClass
    {
        public IList<int> Solution(string s, string[] words)
        {
            List<int> output = [];
            List<string> wordsList = [.. words];
            var wordsLength = words[0].Length; // They have the same length

            // For POS example
            if((new HashSet<string>(words).Count == 1))
            {
                wordsList = [String.Join("", words)];
                wordsLength = wordsList[0].Length;
            }

            if (s.Length < wordsLength * wordsList.Count)
            {
                return output;
            }

            int windowIndex = 0;

            while(windowIndex <= s.Length - (wordsLength*wordsList.Count))
            {
                var substringFromCurrent = s.Substring(windowIndex, wordsLength);
                var substringFromCurrentIndex = wordsList.IndexOf(substringFromCurrent);
                if (substringFromCurrentIndex != -1)
                {
                    var innerWindowIndex = windowIndex + wordsLength;
                    HashSet<int> foundIndices = [substringFromCurrentIndex];
                    while(foundIndices.Count < wordsList.Count)
                    {
                        var nextSubstring = s.Substring(innerWindowIndex, wordsLength);
                        bool foundThisRun = true;
                        for(int i = 0; i < wordsList.Count; i++)
                        {
                            foundThisRun = false;
                            if (foundIndices.Contains(i))
                            {
                                continue;
                            }
                            if (wordsList[i] == nextSubstring)
                            {
                                foundIndices.Add(i);
                                foundThisRun = true;
                                innerWindowIndex += wordsLength;
                                break;
                            }
                        }

                        if (!foundThisRun)
                        {
                            break;
                        }
                    }
                    if (foundIndices.Count == wordsList.Count)
                    {
                        output.Add(windowIndex);
                    }
                }

                windowIndex++;
            }

            return output;
        }

